INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 模擬試験' LIMIT 1), 1, 1, 'reading', '{"title": {"ja": "N5 模擬試験 セット1", "vi": "Đề thi thử N5 Bộ 1"}, "description": {"ja": "JLPT N5レベルの本番形式の模擬試験。語彙、文法、読解の3セクション。時間制限なし。", "vi": "Đề thi thử JLPT N5 theo format thi thật. 3 phần: từ vựng, ngữ pháp, đọc hiểu. Không giới hạn thời gian."}, "total_questions": 30, "passing_score": 18, "questions": [{"question_number": 1, "type": "vocabulary", "question": {"ja": "患者さんは毎日 _____ 薬を飲みます。", "vi": "Bệnh nhân uống _____ thuốc hàng ngày."}, "options": [{"text": {"ja": "ない", "vi": "không"}, "is_correct": false},{"text": {"ja": "ない", "vi": "không"}, "is_correct": false},{"text": {"ja": "て", "vi": "và"}, "is_correct": false},{"text": {"ja": "ます", "vi": "bây giờ"}, "is_correct": true}], "explanation": {"ja": "「毎日～ます」という形で、習慣的な行動を表します。", "vi": "Dạng \"毎日～ます\" biểu hiện hành động thường xuyên."}, "difficulty": "easy"}, {"question_number": 2, "type": "grammar", "question": {"ja": "患者さんが _____ 場所に、ナースステーションがあります。", "vi": "Trạm y tá ở _____ nơi mà bệnh nhân nằm."}, "options": [{"text": {"ja": "いる", "vi": "ở"}, "is_correct": false},{"text": {"ja": "ある", "vi": "có"}, "is_correct": false},{"text": {"ja": "する", "vi": "làm"}, "is_correct": false},{"text": {"ja": "近い", "vi": "gần"}, "is_correct": true}], "explanation": {"ja": "患者さんの場所に近い所に、ナースステーションがあるという意味です。", "vi": "Ý nghĩa là trạm y tá ở gần nơi bệnh nhân nằm."}, "difficulty": "medium"}, {"question_number": 3, "type": "reading", "question": {"ja": "「朝食」の意味は？", "vi": "Ý nghĩa của \"朝食\" là?"}, "options": [{"text": {"ja": "昼食", "vi": "bữa trưa"}, "is_correct": false},{"text": {"ja": "夕食", "vi": "bữa tối"}, "is_correct": false},{"text": {"ja": "朝のご飯", "vi": "bữa sáng"}, "is_correct": true},{"text": {"ja": "夜のご飯", "vi": "bữa tối"}, "is_correct": false}], "explanation": {"ja": "朝食は朝のご飯を意味します。", "vi": "朝食 có nghĩa là bữa ăn sáng."}, "difficulty": "easy"}, {"question_number": 4, "type": "vocabulary", "question": {"ja": "患者さんは立つことが _____ ます。", "vi": "Bệnh nhân _____ đứng dậy."}, "options": [{"text": {"ja": "できます", "vi": "có thể"}, "is_correct": true},{"text": {"ja": "いきます", "vi": "đi"}, "is_correct": false},{"text": {"ja": "います", "vi": "ở"}, "is_correct": false},{"text": {"ja": "あります", "vi": "có"}, "is_correct": false}], "explanation": {"ja": "ことができます は能力を表す表現です。", "vi": "ことができます biểu hiện khả năng."}, "difficulty": "medium"}, {"question_number": 5, "type": "grammar", "question": {"ja": "「明日、散歩に行きませんか？」の返事として、最も適切なものは？", "vi": "Câu trả lời phù hợp nhất cho \"明日、散歩に行きませんか？\" là?"}, "options": [{"text": {"ja": "いいえ、いきません。", "vi": "Không, tôi không đi."}, "is_correct": false},{"text": {"ja": "はい、行きましょう。", "vi": "Vâng, hãy cùng đi."}, "is_correct": true},{"text": {"ja": "散歩は嫌いです。", "vi": "Tôi không thích đi bộ."}, "is_correct": false},{"text": {"ja": "今、散歩しています。", "vi": "Bây giờ tôi đang đi bộ."}, "is_correct": false}], "explanation": {"ja": "勧誘の質問に対しての肯定的な返事は「はい、～ましょう」です。", "vi": "Câu trả lời khẳng định cho lời mời là \"はい、～ましょう\"."}, "difficulty": "medium"}, {"question_number": 6, "type": "vocabulary", "question": {"ja": "お風呂の温度が _____ です。", "vi": "Nhiệt độ bồn tắm là _____."}, "options": [{"text": {"ja": "高い", "vi": "cao"}, "is_correct": true},{"text": {"ja": "低い", "vi": "thấp"}, "is_correct": false},{"text": {"ja": "長い", "vi": "dài"}, "is_correct": false},{"text": {"ja": "短い", "vi": "ngắn"}, "is_correct": false}], "explanation": {"ja": "温度を説明する時は「高い」か「低い」を使います。", "vi": "Khi mô tả nhiệt độ, sử dụng \"高い\" hoặc \"低い\"."}, "difficulty": "easy"}, {"question_number": 7, "type": "reading", "question": {"ja": "「介護」の読み方は？", "vi": "Cách đọc \"介護\" là?"}, "options": [{"text": {"ja": "かいご", "vi": "kaigo"}, "is_correct": true},{"text": {"ja": "いんごう", "vi": "ingou"}, "is_correct": false},{"text": {"ja": "かいぎ", "vi": "kaigi"}, "is_correct": false},{"text": {"ja": "ほごう", "vi": "hogou"}, "is_correct": false}], "explanation": {"ja": "介護は「かいご」と読みます。", "vi": "\"介護\" được đọc là \"かいご\"."}, "difficulty": "easy"}, {"question_number": 8, "type": "grammar", "question": {"ja": "患者さんは足が _____ ます。", "vi": "Bệnh nhân _____ chân."}, "options": [{"text": {"ja": "痛いです", "vi": "đau"}, "is_correct": true},{"text": {"ja": "痛みます", "vi": "gây đau"}, "is_correct": false},{"text": {"ja": "痛さ", "vi": "sự đau"}, "is_correct": false},{"text": {"ja": "痛むことができます", "vi": "có thể đau"}, "is_correct": false}], "explanation": {"ja": "「足が痛い」は症状を表す自然な表現です。", "vi": "\"足が痛い\" là biểu hiện tự nhiên để nói về triệu chứng."}, "difficulty": "medium"}, {"question_number": 9, "type": "vocabulary", "question": {"ja": "患者さんのプライバシーは _____ です。", "vi": "Quyền riêng tư của bệnh nhân là _____."}, "options": [{"text": {"ja": "大切", "vi": "quan trọng"}, "is_correct": true},{"text": {"ja": "不必要", "vi": "không cần thiết"}, "is_correct": false},{"text": {"ja": "危険", "vi": "nguy hiểm"}, "is_correct": false},{"text": {"ja": "複雑", "vi": "phức tạp"}, "is_correct": false}], "explanation": {"ja": "患者さんのプライバシーを守ることは、介護職の大切な責任です。", "vi": "Bảo vệ quyền riêng tư của bệnh nhân là trách nhiệm quan trọng của nhân viên chăm sóc."}, "difficulty": "easy"}, {"question_number": 10, "type": "reading", "question": {"ja": "「回復」の意味に最も近いのは？", "vi": "Ý nghĩa gần nhất với \"回復\" là?"}, "options": [{"text": {"ja": "悪くなる", "vi": "trở nên tồi tệ"}, "is_correct": false},{"text": {"ja": "良くなる", "vi": "trở nên tốt"}, "is_correct": true},{"text": {"ja": "同じままである", "vi": "vẫn như cũ"}, "is_correct": false},{"text": {"ja": "変わらない", "vi": "không thay đổi"}, "is_correct": false}], "explanation": {"ja": "回復は「よくなる」という意味です。", "vi": "回復 có nghĩa là \"trở nên tốt\"."}, "difficulty": "easy"}, {"question_number": 11, "type": "grammar", "question": {"ja": "毎日薬を飲まなければ、病気が _____ ます。", "vi": "Nếu không uống thuốc hàng ngày, bệnh sẽ _____ ."}, "options": [{"text": {"ja": "よくなります", "vi": "lành"}, "is_correct": false},{"text": {"ja": "わかります", "vi": "hiểu"}, "is_correct": false},{"text": {"ja": "悪くなります", "vi": "trở nên tồi tệ"}, "is_correct": true},{"text": {"ja": "できます", "vi": "có thể"}, "is_correct": false}], "explanation": {"ja": "～なければならない は必須の行動を強調し、その結果を説明します。", "vi": "～なければならない nhấn mạnh hành động cần thiết và giải thích hậu quả."}, "difficulty": "medium"}, {"question_number": 12, "type": "vocabulary", "question": {"ja": "患者さんは水を _____ ます。", "vi": "Bệnh nhân _____ nước."}, "options": [{"text": {"ja": "食べます", "vi": "ăn"}, "is_correct": false},{"text": {"ja": "飲みます", "vi": "uống"}, "is_correct": true},{"text": {"ja": "着ます", "vi": "mặc"}, "is_correct": false},{"text": {"ja": "歩きます", "vi": "đi bộ"}, "is_correct": false}], "explanation": {"ja": "飲み物に対しては「飲む」という動詞を使います。", "vi": "Với đồ uống, sử dụng động từ \"飲む\"."}, "difficulty": "easy"}, {"question_number": 13, "type": "reading", "question": {"ja": "「病院」の意味は？", "vi": "Ý nghĩa của \"病院\" là?"}, "options": [{"text": {"ja": "学校", "vi": "trường học"}, "is_correct": false},{"text": {"ja": "医者がいる場所", "vi": "nơi có bác sĩ"}, "is_correct": true},{"text": {"ja": "家", "vi": "nhà"}, "is_correct": false},{"text": {"ja": "公園", "vi": "công viên"}, "is_correct": false}], "explanation": {"ja": "病院は患者さんが治療を受ける場所です。", "vi": "病院 là nơi bệnh nhân nhận điều trị."}, "difficulty": "easy"}, {"question_number": 14, "type": "grammar", "question": {"ja": "「患者さんは今、シャワーを浴びています」この文の意味は？", "vi": "Ý nghĩa của câu \"患者さんは今、シャワーを浴びています\" là?"}, "options": [{"text": {"ja": "患者さんはシャワーを浴びたことがない", "vi": "Bệnh nhân chưa từng tắm"}, "is_correct": false},{"text": {"ja": "患者さんは今、シャワーを浴びている状態である", "vi": "Bệnh nhân đang tắm bây giờ"}, "is_correct": true},{"text": {"ja": "患者さんはシャワーを浴びたい", "vi": "Bệnh nhân muốn tắm"}, "is_correct": false},{"text": {"ja": "患者さんはシャワーを浴びることができない", "vi": "Bệnh nhân không thể tắm"}, "is_correct": false}], "explanation": {"ja": "～ている は現在進行中の状態を表します。", "vi": "～ている biểu hiện hành động đang diễn ra."}, "difficulty": "medium"}, {"question_number": 15, "type": "vocabulary", "question": {"ja": "患者さんの体調は _____ です。", "vi": "Tình trạng sức khỏe của bệnh nhân là _____."}, "options": [{"text": {"ja": "いい", "vi": "tốt"}, "is_correct": true},{"text": {"ja": "食べ物", "vi": "thức ăn"}, "is_correct": false},{"text": {"ja": "動く", "vi": "di chuyển"}, "is_correct": false},{"text": {"ja": "声", "vi": "tiếng"}, "is_correct": false}], "explanation": {"ja": "体調を説明する時は形容詞「いい」「悪い」を使います。", "vi": "Khi mô tả tình trạng sức khỏe, sử dụng tính từ \"いい\" hoặc \"悪い\"."}, "difficulty": "easy"}, {"question_number": 16, "type": "reading", "question": {"ja": "「転倒」の意味は？", "vi": "Ý nghĩa của \"転倒\" là?"}, "options": [{"text": {"ja": "まっすぐ立つ", "vi": "đứng thẳng"}, "is_correct": false},{"text": {"ja": "倒れる、転ぶ", "vi": "ngã, hạ gục"}, "is_correct": true},{"text": {"ja": "走る", "vi": "chạy"}, "is_correct": false},{"text": {"ja": "歩く", "vi": "đi bộ"}, "is_correct": false}], "explanation": {"ja": "転倒は「転ぶ」という意味で、危険な状態です。", "vi": "転倒 có nghĩa là \"ngã\", là một tình trạng nguy hiểm."}, "difficulty": "easy"}, {"question_number": 17, "type": "grammar", "question": {"ja": "「もし～たら」の使い方として、最も適切な文は？", "vi": "Cách sử dụng \"もし～たら\" phù hợp nhất trong câu nào?"}, "options": [{"text": {"ja": "もし病気だったら、医者に行きます。", "vi": "Nếu bị bệnh, tôi sẽ đi gặp bác sĩ."}, "is_correct": true},{"text": {"ja": "もし今、歩いています。", "vi": "Nếu bây giờ tôi đang đi bộ."}, "is_correct": false},{"text": {"ja": "もし毎日、薬を飲みます。", "vi": "Nếu hàng ngày tôi uống thuốc."}, "is_correct": false},{"text": {"ja": "もし昨日、寝ました。", "vi": "Nếu hôm qua tôi đã ngủ."}, "is_correct": false}], "explanation": {"ja": "もし～たら は仮定的な条件を表します。", "vi": "もし～たら biểu hiện điều kiện giả định."}, "difficulty": "medium"}, {"question_number": 18, "type": "vocabulary", "question": {"ja": "患者さんは家族を _____ ます。", "vi": "Bệnh nhân _____ gia đình."}, "options": [{"text": {"ja": "食べます", "vi": "ăn"}, "is_correct": false},{"text": {"ja": "愛します", "vi": "yêu"}, "is_correct": true},{"text": {"ja": "飲みます", "vi": "uống"}, "is_correct": false},{"text": {"ja": "着ます", "vi": "mặc"}, "is_correct": false}], "explanation": {"ja": "「愛する」は「好きである」「大切に思う」という意味です。", "vi": "\"愛する\" có nghĩa là \"thích\" hoặc \"coi trọng\"."}, "difficulty": "medium"}, {"question_number": 19, "type": "reading", "question": {"ja": "文脈から推測して、「いつもお世話になっています」はどういう意味か？", "vi": "Dựa vào ngữ cảnh, \"いつもお世話になっています\" có ý nghĩa gì?"}, "options": [{"text": {"ja": "あなたを困らせています", "vi": "Tôi làm phiền bạn"}, "is_correct": false},{"text": {"ja": "ずっと感謝しています", "vi": "Tôi cảm ơn bạn mãi"}, "is_correct": true},{"text": {"ja": "あなたを手伝いません", "vi": "Tôi không giúp bạn"}, "is_correct": false},{"text": {"ja": "あなたと一緒にいません", "vi": "Tôi không ở cùng bạn"}, "is_correct": false}], "explanation": {"ja": "いつもお世話になっています は継続的な感謝を表す敬語です。", "vi": "いつもお世話になっています biểu hiện sự cảm ơn liên tục bằng từ lịch sự."}, "difficulty": "medium"}, {"question_number": 20, "type": "grammar", "question": {"ja": "「患者さんのほうがスタッフより若いです」この文から、どのことがわかる？", "vi": "Từ câu \"患者さんのほうがスタッフより若いです\", có thể suy ra điều gì?"}, "options": [{"text": {"ja": "患者さんは老人です", "vi": "Bệnh nhân là người cao tuổi"}, "is_correct": false},{"text": {"ja": "スタッフはもっと若いです", "vi": "Nhân viên trẻ hơn"}, "is_correct": false},{"text": {"ja": "患者さんがスタッフより年が少ないです", "vi": "Bệnh nhân trẻ hơn nhân viên"}, "is_correct": true},{"text": {"ja": "患者さんがスタッフと同じ年です", "vi": "Bệnh nhân cùng tuổi với nhân viên"}, "is_correct": false}], "explanation": {"ja": "のほうが～より は比較を表す表現です。前者が後者より～である。", "vi": "のほうが～より là biểu hiện so sánh. Cái trước ~ hơn cái sau."}, "difficulty": "hard"}, {"question_number": 21, "type": "vocabulary", "question": {"ja": "患者さんは朝、 _____ が好きです。", "vi": "Bệnh nhân thích _____ vào sáng."}, "options": [{"text": {"ja": "散歩", "vi": "đi bộ"}, "is_correct": true},{"text": {"ja": "昼寝", "vi": "ngủ trưa"}, "is_correct": false},{"text": {"ja": "夜間", "vi": "ban đêm"}, "is_correct": false},{"text": {"ja": "雨", "vi": "mưa"}, "is_correct": false}], "explanation": {"ja": "朝は「散歩」が自然です。他は朝に相応しくない。", "vi": "\"散歩\" phù hợp với buổi sáng. Những cái khác không thích hợp với buổi sáng."}, "difficulty": "easy"}, {"question_number": 22, "type": "reading", "question": {"ja": "「便秘」と「下痢」は対義語ですか？", "vi": "\"便秘\" và \"下痢\" có phải từ trái nghĩa không?"}, "options": [{"text": {"ja": "はい、対義語です", "vi": "Vâng, là từ trái nghĩa"}, "is_correct": true},{"text": {"ja": "いいえ、同じ意味です", "vi": "Không, cùng ý nghĩa"}, "is_correct": false},{"text": {"ja": "時々対義語です", "vi": "Đôi khi là từ trái nghĩa"}, "is_correct": false},{"text": {"ja": "わかりません", "vi": "Tôi không biết"}, "is_correct": false}], "explanation": {"ja": "便秘は便が出ないこと、下痢は便が出すぎることです。", "vi": "便秘 là không đi vệ sinh, 下痢 là đi vệ sinh quá nhiều."}, "difficulty": "medium"}, {"question_number": 23, "type": "grammar", "question": {"ja": "「患者さんは毎日、血圧を測ることができます」この文は何を意味する？", "vi": "Câu \"患者さんは毎日、血圧を測ることができます\" có ý nghĩa gì?"}, "options": [{"text": {"ja": "患者さんは血圧を測る能力を持っている", "vi": "Bệnh nhân có khả năng đo huyết áp"}, "is_correct": true},{"text": {"ja": "患者さんは血圧を測りたい", "vi": "Bệnh nhân muốn đo huyết áp"}, "is_correct": false},{"text": {"ja": "患者さんは血圧を測る必要がある", "vi": "Bệnh nhân cần phải đo huyết áp"}, "is_correct": false},{"text": {"ja": "患者さんは血圧を測ってはいけない", "vi": "Bệnh nhân không được đo huyết áp"}, "is_correct": false}], "explanation": {"ja": "ことができます は能力や可能性を表します。", "vi": "ことができます biểu hiện khả năng hoặc khả năng."}, "difficulty": "medium"}, {"question_number": 24, "type": "vocabulary", "question": {"ja": "「栄養」の意味は最も近いのは？", "vi": "Ý nghĩa gần nhất với \"栄養\" là?"}, "options": [{"text": {"ja": "食べ物", "vi": "thức ăn"}, "is_correct": false},{"text": {"ja": "健康的な成分", "vi": "thành phần lành mạnh"}, "is_correct": true},{"text": {"ja": "味", "vi": "vị"}, "is_correct": false},{"text": {"ja": "色", "vi": "màu"}, "is_correct": false}], "explanation": {"ja": "栄養は食べ物に含まれる健康に必要な成分です。", "vi": "栄養 là thành phần cần thiết cho sức khỏe chứa trong thực phẩm."}, "difficulty": "easy"}, {"question_number": 25, "type": "reading", "question": {"ja": "「脈拍」の読み方は？", "vi": "Cách đọc \"脈拍\" là?"}, "options": [{"text": {"ja": "すいみゃく", "vi": "suimyaku"}, "is_correct": false},{"text": {"ja": "みゃくはく", "vi": "myakuhaku"}, "is_correct": true},{"text": {"ja": "あつりょく", "vi": "atsuroku"}, "is_correct": false},{"text": {"ja": "こきゅう", "vi": "kokyuu"}, "is_correct": false}], "explanation": {"ja": "脈拍は「みゃくはく」と読みます。", "vi": "\"脈拍\" được đọc là \"みゃくはく\"."}, "difficulty": "easy"}, {"question_number": 26, "type": "grammar", "question": {"ja": "「浴室は滑りやすいです」の反対の意味は？", "vi": "Ý nghĩa đối lập với \"浴室は滑りやすいです\" là?"}, "options": [{"text": {"ja": "浴室は滑りにくいです", "vi": "Phòng tắm khó trượt"}, "is_correct": true},{"text": {"ja": "浴室は滑っています", "vi": "Phòng tắm đang trượt"}, "is_correct": false},{"text": {"ja": "浴室は必要です", "vi": "Phòng tắm là cần thiết"}, "is_correct": false},{"text": {"ja": "浴室は安全です", "vi": "Phòng tắm an toàn"}, "is_correct": false}], "explanation": {"ja": "～やすい の反対は～にくい です。", "vi": "Ngược lại với ~やすい là ~にくい."}, "difficulty": "medium"}, {"question_number": 27, "type": "vocabulary", "question": {"ja": "患者さんの手を _____ ます。", "vi": "Tôi _____ tay bệnh nhân."}, "options": [{"text": {"ja": "握ります", "vi": "nắm"}, "is_correct": true},{"text": {"ja": "飲みます", "vi": "uống"}, "is_correct": false},{"text": {"ja": "食べます", "vi": "ăn"}, "is_correct": false},{"text": {"ja": "見ます", "vi": "nhìn"}, "is_correct": false}], "explanation": {"ja": "手を握る は支援や励ましの身体的な表現です。", "vi": "手を握る là biểu hiện chăm sóc hoặc khuyến khích."}, "difficulty": "easy"}, {"question_number": 28, "type": "reading", "question": {"ja": "介護施設で一日の流れを説明する時、最初は？", "vi": "Khi giải thích quy trình hàng ngày tại cơ sở chăm sóc, điều đầu tiên là?"}, "options": [{"text": {"ja": "夜間に患者さんを起こす", "vi": "Đánh thức bệnh nhân vào ban đêm"}, "is_correct": false},{"text": {"ja": "朝、患者さんを起こす、挨拶をする", "vi": "Sáng, đánh thức bệnh nhân, chào hỏi"}, "is_correct": true},{"text": {"ja": "患者さんが寝ている時に活動をする", "vi": "Hoạt động khi bệnh nhân ngủ"}, "is_correct": false},{"text": {"ja": "患者さんに夕食を与える", "vi": "Cho bệnh nhân ăn tối"}, "is_correct": false}], "explanation": {"ja": "介護の一日は朝の起床と挨拶から始まります。", "vi": "Một ngày chăm sóc bắt đầu từ việc đánh thức bệnh nhân buổi sáng và chào hỏi."}, "difficulty": "medium"}, {"question_number": 29, "type": "grammar", "question": {"ja": "「患者さんが水を飲まなければならません」と「患者さんが水を飲んだほうがいいです」の違いは？", "vi": "Sự khác biệt giữa \"患者さんが水を飲まなければならません\" và \"患者さんが水を飲んだほうがいいです\" là?"}, "options": [{"text": {"ja": "意味が同じである", "vi": "Ý nghĩa giống nhau"}, "is_correct": false},{"text": {"ja": "前者は必須、後者は推奨である", "vi": "Cái trước là bắt buộc, cái sau là khuyến cáo"}, "is_correct": true},{"text": {"ja": "前者は推奨、後者は必須である", "vi": "Cái trước là khuyến cáo, cái sau là bắt buộc"}, "is_correct": false},{"text": {"ja": "二つとも推奨である", "vi": "Cả hai đều là khuyến cáo"}, "is_correct": false}], "explanation": {"ja": "なければならない は強い義務、ほうがいい は柔らかい推奨です。", "vi": "なければならない là bắt buộc mạnh, ほうがいい là khuyến cáo mềm mỏng."}, "difficulty": "hard"}, {"question_number": 30, "type": "reading", "question": {"ja": "「患者さんの回復が順調です」の文から、患者さんについて何がわかりますか？", "vi": "Từ câu \"患者さんの回復が順調です\", có thể suy ra điều gì về bệnh nhân?"}, "options": [{"text": {"ja": "患者さんは悪くなっている", "vi": "Bệnh nhân đang xấu đi"}, "is_correct": false},{"text": {"ja": "患者さんは良くなっている", "vi": "Bệnh nhân đang tốt lên"}, "is_correct": true},{"text": {"ja": "患者さんは変わっていない", "vi": "Bệnh nhân không thay đổi"}, "is_correct": false},{"text": {"ja": "患者さんは医者に行かない", "vi": "Bệnh nhân không đi gặp bác sĩ"}, "is_correct": false}], "explanation": {"ja": "回復が順調 は患者さんが良くなっている状態を表します。", "vi": "回復が順調 biểu hiện bệnh nhân đang tốt lên."}, "difficulty": "easy"}]}' );

