INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 模擬試験' LIMIT 1), 2, 1, 'reading', '{"title": {"ja": "N5 模擬試験 セット2", "vi": "Đề thi thử N5 Bộ 2"}, "description": {"ja": "JLPT N5レベルの本番形式の模擬試験。セット2。語彙、文法、読解の3セクション。", "vi": "Đề thi thử JLPT N5 theo format thi thật. Bộ 2. 3 phần: từ vựng, ngữ pháp, đọc hiểu."}, "total_questions": 30, "passing_score": 18, "questions": [{"question_number": 1, "type": "vocabulary", "question": {"ja": "毎日、患者さんは _____ を歩きます。", "vi": "Hàng ngày, bệnh nhân đi bộ _____."}, "options": [{"text": {"ja": "15分", "vi": "15 phút"}, "is_correct": true},{"text": {"ja": "15個", "vi": "15 cái"}, "is_correct": false},{"text": {"ja": "15番", "vi": "số 15"}, "is_correct": false},{"text": {"ja": "15回", "vi": "15 lần"}, "is_correct": false}], "explanation": {"ja": "時間の長さは「分」を使います。", "vi": "Thời gian sử dụng \"分\"."}, "difficulty": "easy"}, {"question_number": 2, "type": "grammar", "question": {"ja": "患者さんは昨日、 _____ 医者に行きました。", "vi": "Bệnh nhân _____ đi gặp bác sĩ hôm qua."}, "options": [{"text": {"ja": "いっしょに", "vi": "cùng"}, "is_correct": true},{"text": {"ja": "ひとりで", "vi": "một mình"}, "is_correct": false},{"text": {"ja": "毎日", "vi": "hàng ngày"}, "is_correct": false},{"text": {"ja": "すぐに", "vi": "ngay lập tức"}, "is_correct": false}], "explanation": {"ja": "文脈から、誰かと一緒に医者に行ったことがわかります。", "vi": "Từ ngữ cảnh, có thể suy ra rằng bệnh nhân đi gặp bác sĩ cùng với ai đó."}, "difficulty": "medium"}, {"question_number": 3, "type": "reading", "question": {"ja": "「呑み込む」の意味は？", "vi": "Ý nghĩa của \"呑み込む\" là?"}, "options": [{"text": {"ja": "飲む", "vi": "uống"}, "is_correct": false},{"text": {"ja": "食べ物をのどを通す、嚥下する", "vi": "Nuốt, ngụp"}, "is_correct": true},{"text": {"ja": "話す", "vi": "nói"}, "is_correct": false},{"text": {"ja": "聞く", "vi": "nghe"}, "is_correct": false}], "explanation": {"ja": "呑み込むは医療用語で、食べ物を飲む動作です。", "vi": "呑み込む là thuật ngữ y tế cho hành động nuốt thực phẩm."}, "difficulty": "medium"}, {"question_number": 4, "type": "vocabulary", "question": {"ja": "患者さんの症状は _____ です。", "vi": "Triệu chứng của bệnh nhân là _____."}, "options": [{"text": {"ja": "悪い", "vi": "tồi tệ"}, "is_correct": true},{"text": {"ja": "美しい", "vi": "đẹp"}, "is_correct": false},{"text": {"ja": "速い", "vi": "nhanh"}, "is_correct": false},{"text": {"ja": "楽しい", "vi": "vui"}, "is_correct": false}], "explanation": {"ja": "症状を説明する時は「悪い」「良い」などの形容詞を使います。", "vi": "Khi mô tả triệu chứng, sử dụng các tính từ như \"悪い\" hoặc \"良い\"."}, "difficulty": "easy"}, {"question_number": 5, "type": "grammar", "question": {"ja": "「患者さんは手すりを _____ 階段を上ります。」に最も適切なのは？", "vi": "Để hoàn thành câu \"患者さんは手すりを _____ 階段を上ります\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "持って", "vi": "nắm"}, "is_correct": true},{"text": {"ja": "食べて", "vi": "ăn"}, "is_correct": false},{"text": {"ja": "飲んで", "vi": "uống"}, "is_correct": false},{"text": {"ja": "見て", "vi": "nhìn"}, "is_correct": false}], "explanation": {"ja": "手すりを持って階段を上る は安全に移動するための行動です。", "vi": "手すりを持って階段を上る là hành động di chuyển an toàn."}, "difficulty": "medium"}, {"question_number": 6, "type": "vocabulary", "question": {"ja": "患者さんは今日、 _____ を着ました。", "vi": "Hôm nay, bệnh nhân mặc _____."}, "options": [{"text": {"ja": "服", "vi": "quần áo"}, "is_correct": true},{"text": {"ja": "食べ物", "vi": "thực phẩm"}, "is_correct": false},{"text": {"ja": "薬", "vi": "thuốc"}, "is_correct": false},{"text": {"ja": "水", "vi": "nước"}, "is_correct": false}], "explanation": {"ja": "衣類に対しては「着る」という動詞を使います。", "vi": "Với quần áo, sử dụng động từ \"着る\"."}, "difficulty": "easy"}, {"question_number": 7, "type": "reading", "question": {"ja": "「お疲れ様です」はどの場面で使う？", "vi": "\"お疲れ様です\" được sử dụng trong tình huống nào?"}, "options": [{"text": {"ja": "相手の努力や仕事をねぎらう時", "vi": "Khi biểu tỏ sự kính trọng đối với nỗ lực hoặc công việc của người khác"}, "is_correct": true},{"text": {"ja": "相手を怒る時", "vi": "Khi tức giận người khác"}, "is_correct": false},{"text": {"ja": "相手を笑う時", "vi": "Khi cười người khác"}, "is_correct": false},{"text": {"ja": "相手と争う時", "vi": "Khi tranh cải với người khác"}, "is_correct": false}], "explanation": {"ja": "お疲れ様です は相手の頑張りを認める敬語です。", "vi": "お疲れ様です là từ lịch sự để công nhận nỗ lực của người khác."}, "difficulty": "medium"}, {"question_number": 8, "type": "grammar", "question": {"ja": "「患者さんは毎日、 _____ 薬を飲みます。」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんは毎日、 _____ 薬を飲みます\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "決まった時間に", "vi": "vào giờ định"}, "is_correct": true},{"text": {"ja": "たまに", "vi": "thỉnh thoảng"}, "is_correct": false},{"text": {"ja": "寝る時に", "vi": "lúc ngủ"}, "is_correct": false},{"text": {"ja": "好きな時に", "vi": "lúc thích"}, "is_correct": false}], "explanation": {"ja": "毎日の薬は決まった時間に飲む必要があります。", "vi": "Thuốc hàng ngày cần uống vào giờ định."}, "difficulty": "medium"}, {"question_number": 9, "type": "vocabulary", "question": {"ja": "患者さんのプライバシーを _____ ます。", "vi": "Tôi _____ quyền riêng tư của bệnh nhân."}, "options": [{"text": {"ja": "守ります", "vi": "bảo vệ"}, "is_correct": true},{"text": {"ja": "忘れます", "vi": "quên"}, "is_correct": false},{"text": {"ja": "失います", "vi": "mất"}, "is_correct": false},{"text": {"ja": "変えます", "vi": "thay đổi"}, "is_correct": false}], "explanation": {"ja": "プライバシーを守る は重要な義務です。", "vi": "Bảo vệ quyền riêng tư là bổn phận quan trọng."}, "difficulty": "easy"}, {"question_number": 10, "type": "reading", "question": {"ja": "「一口」の意味は？", "vi": "Ý nghĩa của \"一口\" là?"}, "options": [{"text": {"ja": "口全体", "vi": "toàn bộ miệng"}, "is_correct": false},{"text": {"ja": "口の開き", "vi": "độ mở của miệng"}, "is_correct": false},{"text": {"ja": "一度の食べ物の量", "vi": "Lượng thức ăn một lần"}, "is_correct": true},{"text": {"ja": "口の病気", "vi": "bệnh miệng"}, "is_correct": false}], "explanation": {"ja": "一口は「ひとくち」と読み、一度に口に入れる量です。", "vi": "一口 (ひとくち) là lượng thức ăn một lần."}, "difficulty": "easy"}, {"question_number": 11, "type": "grammar", "question": {"ja": "「患者さんは足が痛いので、歩きません」この「ので」の意味は？", "vi": "Ý nghĩa của \"ので\" trong \"患者さんは足が痛いので、歩きません\" là?"}, "options": [{"text": {"ja": "目的である", "vi": "là mục đích"}, "is_correct": false},{"text": {"ja": "原因・理由である", "vi": "là nguyên nhân/lý do"}, "is_correct": true},{"text": {"ja": "時間である", "vi": "là thời gian"}, "is_correct": false},{"text": {"ja": "場所である", "vi": "là địa điểm"}, "is_correct": false}], "explanation": {"ja": "ので は理由や原因を表します。", "vi": "ので biểu hiện lý do hoặc nguyên nhân."}, "difficulty": "medium"}, {"question_number": 12, "type": "vocabulary", "question": {"ja": "患者さんは朝、 _____ を測ります。", "vi": "Sáng, bệnh nhân đo _____."}, "options": [{"text": {"ja": "体温", "vi": "thân nhiệt"}, "is_correct": true},{"text": {"ja": "香り", "vi": "mùi"}, "is_correct": false},{"text": {"ja": "色", "vi": "màu"}, "is_correct": false},{"text": {"ja": "音", "vi": "âm thanh"}, "is_correct": false}], "explanation": {"ja": "朝は患者さんの健康チェックとして体温を測ります。", "vi": "Sáng hôm đó để kiểm tra sức khỏe, đo thân nhiệt bệnh nhân."}, "difficulty": "easy"}, {"question_number": 13, "type": "reading", "question": {"ja": "「手洗い」はなぜ大事ですか？", "vi": "Tại sao \"手洗い\" lại quan trọng?"}, "options": [{"text": {"ja": "気持ちいいから", "vi": "Vì thoải mái"}, "is_correct": false},{"text": {"ja": "感染症を防ぐため", "vi": "Để phòng chống bệnh lây nhiễm"}, "is_correct": true},{"text": {"ja": "時間を過ごすため", "vi": "Để dành thời gian"}, "is_correct": false},{"text": {"ja": "皮膚を柔らかくするため", "vi": "Để làm mềm da"}, "is_correct": false}], "explanation": {"ja": "手洗いは感染症予防の基本です。", "vi": "Rửa tay là cơ bản để phòng chống bệnh lây nhiễm."}, "difficulty": "easy"}, {"question_number": 14, "type": "grammar", "question": {"ja": "「もし転んだら、すぐに言ってください」この「もし」の役割は？", "vi": "Vai trò của \"もし\" trong \"もし転んだら、すぐに言ってください\" là?"}, "options": [{"text": {"ja": "確定である", "vi": "là xác nhận"}, "is_correct": false},{"text": {"ja": "仮定である", "vi": "là giả định"}, "is_correct": true},{"text": {"ja": "命令である", "vi": "là lệnh"}, "is_correct": false},{"text": {"ja": "提案である", "vi": "là đề xuất"}, "is_correct": false}], "explanation": {"ja": "もし は仮定的な状況を表すよりあります。", "vi": "もし biểu hiện tình huống giả định."}, "difficulty": "medium"}, {"question_number": 15, "type": "vocabulary", "question": {"ja": "患者さんの _____ が高いです。", "vi": "_____ của bệnh nhân cao."}, "options": [{"text": {"ja": "血圧", "vi": "huyết áp"}, "is_correct": true},{"text": {"ja": "気分", "vi": "tâm trạng"}, "is_correct": false},{"text": {"ja": "知識", "vi": "kiến thức"}, "is_correct": false},{"text": {"ja": "能力", "vi": "khả năng"}, "is_correct": false}], "explanation": {"ja": "血圧が高い は医療的な状態です。", "vi": "血圧が高い là tình trạng y tế."}, "difficulty": "easy"}, {"question_number": 16, "type": "reading", "question": {"ja": "「申し送り」の主な目的は？", "vi": "Mục đích chính của \"申し送り\" là?"}, "options": [{"text": {"ja": "患者さんを怖がらせる", "vi": "Làm bệnh nhân sợ"}, "is_correct": false},{"text": {"ja": "患者さんの情報を次のシフトに伝える", "vi": "Chuyển giao thông tin bệnh nhân cho ca làm việc tiếp theo"}, "is_correct": true},{"text": {"ja": "スタッフの秘密を共有する", "vi": "Chia sẻ bí mật của nhân viên"}, "is_correct": false},{"text": {"ja": "患者さんについて悪く言う", "vi": "Nói xấu về bệnh nhân"}, "is_correct": false}], "explanation": {"ja": "申し送りは患者さんの安全と継続的なケアのためです。", "vi": "申し送り là để đảm bảo an toàn bệnh nhân và chăm sóc liên tục."}, "difficulty": "medium"}, {"question_number": 17, "type": "grammar", "question": {"ja": "「患者さんが好きな食べ物は何ですか？」の「が」の役割は？", "vi": "Vai trò của \"が\" trong \"患者さんが好きな食べ物は何ですか？\" là?"}, "options": [{"text": {"ja": "目的である", "vi": "là mục đích"}, "is_correct": false},{"text": {"ja": "対象である", "vi": "là đối tượng"}, "is_correct": true},{"text": {"ja": "手段である", "vi": "là phương tiện"}, "is_correct": false},{"text": {"ja": "理由である", "vi": "là lý do"}, "is_correct": false}], "explanation": {"ja": "好きな場合は「が」を使います。対象を示します。", "vi": "Với \"好きな\", sử dụng \"が\". Nó chỉ đối tượng."}, "difficulty": "hard"}, {"question_number": 18, "type": "vocabulary", "question": {"ja": "患者さんは入浴後、 _____ で体をふきます。", "vi": "Sau tắm, bệnh nhân lau cơ thể bằng _____."}, "options": [{"text": {"ja": "タオル", "vi": "khăn"}, "is_correct": true},{"text": {"ja": "石鹸", "vi": "xà phòng"}, "is_correct": false},{"text": {"ja": "薬", "vi": "thuốc"}, "is_correct": false},{"text": {"ja": "水", "vi": "nước"}, "is_correct": false}], "explanation": {"ja": "タオルは体を拭くために使う布です。", "vi": "タオル là tấm vải dùng để lau cơ thể."}, "difficulty": "easy"}, {"question_number": 19, "type": "reading", "question": {"ja": "「食べやすい」の意味は？", "vi": "Ý nghĩa của \"食べやすい\" là?"}, "options": [{"text": {"ja": "食べ物が美しい", "vi": "Thức ăn đẹp"}, "is_correct": false},{"text": {"ja": "食べるのが簡単である", "vi": "Dễ ăn"}, "is_correct": true},{"text": {"ja": "食べるのが難しい", "vi": "Khó ăn"}, "is_correct": false},{"text": {"ja": "食べたくない", "vi": "Không muốn ăn"}, "is_correct": false}], "explanation": {"ja": "食べやすい は「簡単に食べられる」という意味です。", "vi": "食べやすい có nghĩa là \"dễ ăn\"."}, "difficulty": "easy"}, {"question_number": 20, "type": "grammar", "question": {"ja": "「患者さんは毎晩、寝る前に薬を飲みます」の「前に」の意味は？", "vi": "Ý nghĩa của \"前に\" trong \"患者さんは毎晩、寝る前に薬を飲みます\" là?"}, "options": [{"text": {"ja": "時間的に先である", "vi": "sớm hơn về thời gian"}, "is_correct": true},{"text": {"ja": "空間的に前である", "vi": "phía trước về không gian"}, "is_correct": false},{"text": {"ja": "理由である", "vi": "là lý do"}, "is_correct": false},{"text": {"ja": "目的である", "vi": "là mục đích"}, "is_correct": false}], "explanation": {"ja": "寝る前に は「寝るより先に」という時間的な関係です。", "vi": "寝る前に có nghĩa là \"trước khi ngủ\"."}, "difficulty": "medium"}, {"question_number": 21, "type": "vocabulary", "question": {"ja": "患者さんは _____ ない場所に、危険なものを置かないでください。", "vi": "Đừng đặt những thứ nguy hiểm nơi bệnh nhân _____ ."}, "options": [{"text": {"ja": "手が届く", "vi": "tay với tới"}, "is_correct": true},{"text": {"ja": "目が見える", "vi": "mắt nhìn thấy"}, "is_correct": false},{"text": {"ja": "心が感じる", "vi": "trái tim cảm nhận"}, "is_correct": false},{"text": {"ja": "耳が聞こえる", "vi": "tai nghe thấy"}, "is_correct": false}], "explanation": {"ja": "危険な物は患者さんが手を伸ばして取れない場所に置きます。", "vi": "Đặt những thứ nguy hiểm nơi bệnh nhân không thể với tới."}, "difficulty": "medium"}, {"question_number": 22, "type": "reading", "question": {"ja": "「異常」と「正常」は対義語ですか？", "vi": "\"異常\" và \"正常\" có phải từ trái nghĩa không?"}, "options": [{"text": {"ja": "はい、対義語です", "vi": "Vâng, là từ trái nghĩa"}, "is_correct": true},{"text": {"ja": "いいえ、同じ意味です", "vi": "Không, cùng ý nghĩa"}, "is_correct": false},{"text": {"ja": "時々対義語です", "vi": "Đôi khi là từ trái nghĩa"}, "is_correct": false},{"text": {"ja": "わかりません", "vi": "Tôi không biết"}, "is_correct": false}], "explanation": {"ja": "異常は「通常と違う」、正常は「通常である」です。", "vi": "異常 là \"khác thường\", 正常 là \"bình thường\"."}, "difficulty": "easy"}, {"question_number": 23, "type": "grammar", "question": {"ja": "「患者さんは走ることができません」この文は何を意味する？", "vi": "Câu \"患者さんは走ることができません\" có ý nghĩa gì?"}, "options": [{"text": {"ja": "患者さんは走る能力を持たない", "vi": "Bệnh nhân không có khả năng chạy"}, "is_correct": true},{"text": {"ja": "患者さんは走りたくない", "vi": "Bệnh nhân không muốn chạy"}, "is_correct": false},{"text": {"ja": "患者さんは走る必要がある", "vi": "Bệnh nhân cần phải chạy"}, "is_correct": false},{"text": {"ja": "患者さんは走っている", "vi": "Bệnh nhân đang chạy"}, "is_correct": false}], "explanation": {"ja": "ことができない は能力がないことを表します。", "vi": "ことができない biểu hiện không có khả năng."}, "difficulty": "medium"}, {"question_number": 24, "type": "vocabulary", "question": {"ja": "患者さんは今日、 _____ が悪いです。", "vi": "Hôm nay, bệnh nhân _____ không tốt."}, "options": [{"text": {"ja": "気分", "vi": "tâm trạng"}, "is_correct": true},{"text": {"ja": "家", "vi": "nhà"}, "is_correct": false},{"text": {"ja": "天気", "vi": "thời tiết"}, "is_correct": false},{"text": {"ja": "本", "vi": "sách"}, "is_correct": false}], "explanation": {"ja": "気分が悪い は患者さんの身体的または精神的な状態を表します。", "vi": "気分が悪い biểu hiện tình trạng thể chất hoặc tinh thần."}, "difficulty": "easy"}, {"question_number": 25, "type": "reading", "question": {"ja": "「呼吸」の読み方は？", "vi": "Cách đọc \"呼吸\" là?"}, "options": [{"text": {"ja": "こきゅう", "vi": "kokyuu"}, "is_correct": true},{"text": {"ja": "すいみゃく", "vi": "suimyaku"}, "is_correct": false},{"text": {"ja": "あつりょく", "vi": "atsuroku"}, "is_correct": false},{"text": {"ja": "みゃくはく", "vi": "myakuhaku"}, "is_correct": false}], "explanation": {"ja": "呼吸は「こきゅう」と読みます。", "vi": "\"呼吸\" được đọc là \"こきゅう\"."}, "difficulty": "easy"}, {"question_number": 26, "type": "grammar", "question": {"ja": "「患者さんの回復がとてもいいので、退院できます」の「ので」の役割は？", "vi": "Vai trò của \"ので\" trong \"患者さんの回復がとてもいいので、退院できます\" là?"}, "options": [{"text": {"ja": "原因・理由である", "vi": "là nguyên nhân/lý do"}, "is_correct": true},{"text": {"ja": "目的である", "vi": "là mục đích"}, "is_correct": false},{"text": {"ja": "時間である", "vi": "là thời gian"}, "is_correct": false},{"text": {"ja": "場所である", "vi": "là địa điểm"}, "is_correct": false}], "explanation": {"ja": "ので は原因や理由を表す接続詞です。", "vi": "ので là liên từ biểu hiện nguyên nhân hoặc lý do."}, "difficulty": "medium"}, {"question_number": 27, "type": "vocabulary", "question": {"ja": "患者さんは家族と _____ に行きました。", "vi": "Bệnh nhân đi _____ với gia đình."}, "options": [{"text": {"ja": "病院", "vi": "bệnh viện"}, "is_correct": false},{"text": {"ja": "公園", "vi": "công viên"}, "is_correct": true},{"text": {"ja": "薬局", "vi": "hiệu thuốc"}, "is_correct": false},{"text": {"ja": "寝室", "vi": "phòng ngủ"}, "is_correct": false}], "explanation": {"ja": "家族と一緒に行く場所として、公園が自然です。", "vi": "Công viên là nơi tự nhiên để đi cùng gia đình."}, "difficulty": "easy"}, {"question_number": 28, "type": "reading", "question": {"ja": "患者さんが説明を理解しない場合、介護職は？", "vi": "Nếu bệnh nhân không hiểu lời giải thích, nhân viên chăm sóc nên?"}, "options": [{"text": {"ja": "患者さんを無視する", "vi": "Bỏ qua bệnh nhân"}, "is_correct": false},{"text": {"ja": "丁寧に説明し直す", "vi": "Giải thích lại một cách chu đáo"}, "is_correct": true},{"text": {"ja": "患者さんに怒る", "vi": "Tức giận bệnh nhân"}, "is_correct": false},{"text": {"ja": "患者さんの話を聞かない", "vi": "Không nghe lời của bệnh nhân"}, "is_correct": false}], "explanation": {"ja": "患者さんの理解を確認し、丁寧に説明し直すことが大切です。", "vi": "Xác nhận sự hiểu biết của bệnh nhân và giải thích lại một cách chu đáo là cần thiết."}, "difficulty": "medium"}, {"question_number": 29, "type": "grammar", "question": {"ja": "「患者さんは運動することが好きです」と「患者さんは運動することができます」の違いは？", "vi": "Sự khác biệt giữa \"患者さんは運動することが好きです\" và \"患者さんは運動することができます\" là?"}, "options": [{"text": {"ja": "意味が同じである", "vi": "Ý nghĩa giống nhau"}, "is_correct": false},{"text": {"ja": "前者は好きであり、後者は能力を示す", "vi": "Cái trước biểu hiện sở thích, cái sau biểu hiện khả năng"}, "is_correct": true},{"text": {"ja": "前者は能力であり、後者は好きを示す", "vi": "Cái trước biểu hiện khả năng, cái sau biểu hiện sở thích"}, "is_correct": false},{"text": {"ja": "両方とも好きを意味する", "vi": "Cả hai đều biểu hiện sở thích"}, "is_correct": false}], "explanation": {"ja": "好きです は感情、ことができます は能力を表します。", "vi": "好きです biểu hiện cảm xúc, ことができます biểu hiện khả năng."}, "difficulty": "hard"}, {"question_number": 30, "type": "reading", "question": {"ja": "「患者さんのご様子をお伝えします」から、何が推測できますか？", "vi": "Từ \"患者さんのご様子をお伝えします\", có thể suy ra điều gì?"}, "options": [{"text": {"ja": "患者さんについて何も話さない", "vi": "Không nói gì về bệnh nhân"}, "is_correct": false},{"text": {"ja": "患者さんの状態について説明する予定である", "vi": "Dự định giải thích tình trạng bệnh nhân"}, "is_correct": true},{"text": {"ja": "患者さんを批判する", "vi": "Phê bình bệnh nhân"}, "is_correct": false},{"text": {"ja": "患者さんの秘密を広める", "vi": "Phổ biến bí mật của bệnh nhân"}, "is_correct": false}], "explanation": {"ja": "ご様子をお伝えします は患者さんの状態を丁寧に説明することを示します。", "vi": "ご様子をお伝えします biểu hiện dự định giải thích chu đáo tình trạng bệnh nhân."}, "difficulty": "easy"}]}' );

