INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 模擬試験' LIMIT 1), 3, 1, 'reading', '{"title": {"ja": "N5 模擬試験 セット3", "vi": "Đề thi thử N5 Bộ 3"}, "description": {"ja": "JLPT N5レベルの本番形式の模擬試験。セット3。語彙、文法、読解の最終チャレンジ。", "vi": "Đề thi thử JLPT N5 theo format thi thật. Bộ 3. 3 phần: từ vựng, ngữ pháp, đọc hiểu (bài kiểm tra cuối cùng)."}, "total_questions": 30, "passing_score": 18, "questions": [{"question_number": 1, "type": "vocabulary", "question": {"ja": "患者さんは毎朝、 _____ を飲みます。", "vi": "Mỗi sáng, bệnh nhân uống _____."}, "options": [{"text": {"ja": "水", "vi": "nước"}, "is_correct": true},{"text": {"ja": "石鹸", "vi": "xà phòng"}, "is_correct": false},{"text": {"ja": "薬", "vi": "thuốc"}, "is_correct": false},{"text": {"ja": "タオル", "vi": "khăn"}, "is_correct": false}], "explanation": {"ja": "毎朝、患者さんが飲む物として、水が自然です。", "vi": "Mỗi sáng, nước là tự nhiên cho bệnh nhân uống."}, "difficulty": "easy"}, {"question_number": 2, "type": "grammar", "question": {"ja": "「患者さんは今、 _____ 状態です。」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんは今、 _____ 状態です\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "いい", "vi": "tốt"}, "is_correct": true},{"text": {"ja": "吃る", "vi": "nói lắp"}, "is_correct": false},{"text": {"ja": "走る", "vi": "chạy"}, "is_correct": false},{"text": {"ja": "着る", "vi": "mặc"}, "is_correct": false}], "explanation": {"ja": "状態を説明する時は形容詞を使います。", "vi": "Khi mô tả tình trạng, sử dụng tính từ."}, "difficulty": "medium"}, {"question_number": 3, "type": "reading", "question": {"ja": "「複雑」の反対の意味は？", "vi": "Ý nghĩa đối lập với \"複雑\" là?"}, "options": [{"text": {"ja": "難しい", "vi": "khó"}, "is_correct": false},{"text": {"ja": "単純", "vi": "đơn giản"}, "is_correct": true},{"text": {"ja": "面白い", "vi": "thú vị"}, "is_correct": false},{"text": {"ja": "重い", "vi": "nặng"}, "is_correct": false}], "explanation": {"ja": "複雑と単純は対義語です。", "vi": "複雑 và 単純 là từ trái nghĩa."}, "difficulty": "easy"}, {"question_number": 4, "type": "vocabulary", "question": {"ja": "患者さんは _____ ことが大事です。", "vi": "Điều quan trọng là bệnh nhân _____."}, "options": [{"text": {"ja": "毎日、運動する", "vi": "tập thể dục hàng ngày"}, "is_correct": true},{"text": {"ja": "毎日、寝る", "vi": "ngủ hàng ngày"}, "is_correct": false},{"text": {"ja": "毎日、食べる", "vi": "ăn hàng ngày"}, "is_correct": false},{"text": {"ja": "毎日、テレビを見る", "vi": "xem TV hàng ngày"}, "is_correct": false}], "explanation": {"ja": "患者さんの健康のために、毎日の運動が大事です。", "vi": "Để sức khỏe của bệnh nhân, tập thể dục hàng ngày rất quan trọng."}, "difficulty": "easy"}, {"question_number": 5, "type": "grammar", "question": {"ja": "「患者さんが食べた後、 _____ をしてください。」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんが食べた後、 _____ をしてください\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "手洗い", "vi": "rửa tay"}, "is_correct": true},{"text": {"ja": "散歩", "vi": "đi bộ"}, "is_correct": false},{"text": {"ja": "シャワー", "vi": "vòi sen"}, "is_correct": false},{"text": {"ja": "睡眠", "vi": "ngủ"}, "is_correct": false}], "explanation": {"ja": "食べた後、手洗いは感染症予防です。", "vi": "Sau khi ăn, rửa tay để phòng chống bệnh lây nhiễm."}, "difficulty": "medium"}, {"question_number": 6, "type": "vocabulary", "question": {"ja": "患者さんは _____ に近い所に、危ないものを置かないでください。", "vi": "Đừng đặt những thứ nguy hiểm gần _____."}, "options": [{"text": {"ja": "患者さん", "vi": "bệnh nhân"}, "is_correct": true},{"text": {"ja": "医者", "vi": "bác sĩ"}, "is_correct": false},{"text": {"ja": "家族", "vi": "gia đình"}, "is_correct": false},{"text": {"ja": "スタッフ", "vi": "nhân viên"}, "is_correct": false}], "explanation": {"ja": "患者さんの安全が最優先です。", "vi": "An toàn của bệnh nhân là ưu tiên hàng đầu."}, "difficulty": "easy"}, {"question_number": 7, "type": "reading", "question": {"ja": "「親密」の意味に最も近いのは？", "vi": "Ý nghĩa gần nhất với \"親密\" là?"}, "options": [{"text": {"ja": "遠い関係", "vi": "mối quan hệ xa"}, "is_correct": false},{"text": {"ja": "親しい関係", "vi": "mối quan hệ gần gũi"}, "is_correct": true},{"text": {"ja": "敵の関係", "vi": "mối quan hệ thù địch"}, "is_correct": false},{"text": {"ja": "知らない関係", "vi": "mối quan hệ không quen"}, "is_correct": false}], "explanation": {"ja": "親密は「親しい」という意味です。", "vi": "親密 có nghĩa là \"gần gũi\"."}, "difficulty": "easy"}, {"question_number": 8, "type": "grammar", "question": {"ja": "「患者さんが _____ ないで、出かけました」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんが _____ ないで、出かけました\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "朝食を食べ", "vi": "ăn sáng"}, "is_correct": true},{"text": {"ja": "薬を飲み", "vi": "uống thuốc"}, "is_correct": false},{"text": {"ja": "入浴し", "vi": "tắm"}, "is_correct": false},{"text": {"ja": "散歩し", "vi": "đi bộ"}, "is_correct": false}], "explanation": {"ja": "朝食を食べないで出かけるのは健康に良くありません。", "vi": "Đi ra ngoài mà không ăn sáng là không tốt cho sức khỏe."}, "difficulty": "medium"}, {"question_number": 9, "type": "vocabulary", "question": {"ja": "患者さんの _____ を大切にしてください。", "vi": "Vui lòng trân trọng _____ của bệnh nhân."}, "options": [{"text": {"ja": "気持ち", "vi": "cảm xúc"}, "is_correct": true},{"text": {"ja": "色", "vi": "màu"}, "is_correct": false},{"text": {"ja": "重さ", "vi": "trọng lượng"}, "is_correct": false},{"text": {"ja": "匂い", "vi": "mùi"}, "is_correct": false}], "explanation": {"ja": "患者さんの気持ちを理解し、尊重することが大切です。", "vi": "Hiểu và tôn trọng cảm xúc của bệnh nhân rất quan trọng."}, "difficulty": "medium"}, {"question_number": 10, "type": "reading", "question": {"ja": "「優雅」と「粗い」は対義語ですか？", "vi": "\"優雅\" và \"粗い\" có phải từ trái nghĩa không?"}, "options": [{"text": {"ja": "はい、対義語です", "vi": "Vâng, là từ trái nghĩa"}, "is_correct": true},{"text": {"ja": "いいえ、同じ意味です", "vi": "Không, cùng ý nghĩa"}, "is_correct": false},{"text": {"ja": "時々対義語です", "vi": "Đôi khi là từ trái nghĩa"}, "is_correct": false},{"text": {"ja": "わかりません", "vi": "Tôi không biết"}, "is_correct": false}], "explanation": {"ja": "優雅は「上品である」、粗いは「雑である」です。", "vi": "優雅 là \"thanh lịch\", 粗い là \"thô sơ\"."}, "difficulty": "medium"}, {"question_number": 11, "type": "grammar", "question": {"ja": "「患者さんは毎日、 _____ ために、薬を飲みます。」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんは毎日、 _____ ために、薬を飲みます\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "健康でいる", "vi": "khỏe mạnh"}, "is_correct": true},{"text": {"ja": "病気になる", "vi": "bị bệnh"}, "is_correct": false},{"text": {"ja": "睡眠する", "vi": "ngủ"}, "is_correct": false},{"text": {"ja": "散歩する", "vi": "đi bộ"}, "is_correct": false}], "explanation": {"ja": "ために は目的を表します。患者さんは健康を保つために薬を飲みます。", "vi": "ために biểu hiện mục đích. Bệnh nhân uống thuốc để giữ sức khỏe."}, "difficulty": "medium"}, {"question_number": 12, "type": "vocabulary", "question": {"ja": "患者さんは _____ さんと、よく話します。", "vi": "Bệnh nhân thường nói chuyện với _____ ."}, "options": [{"text": {"ja": "家族", "vi": "gia đình"}, "is_correct": true},{"text": {"ja": "敵", "vi": "kẻ thù"}, "is_correct": false},{"text": {"ja": "怖い人", "vi": "người đáng sợ"}, "is_correct": false},{"text": {"ja": "他人", "vi": "người lạ"}, "is_correct": false}], "explanation": {"ja": "患者さんが安心して話す相手として、家族が自然です。", "vi": "Gia đình là người tự nhiên mà bệnh nhân an tâm nói chuyện."}, "difficulty": "easy"}, {"question_number": 13, "type": "reading", "question": {"ja": "「繰り返す」の意味は？", "vi": "Ý nghĩa của \"繰り返す\" là?"}, "options": [{"text": {"ja": "一度だけする", "vi": "Làm một lần"}, "is_correct": false},{"text": {"ja": "何度も同じことをする", "vi": "Làm cùng một việc nhiều lần"}, "is_correct": true},{"text": {"ja": "全くしない", "vi": "Hoàn toàn không làm"}, "is_correct": false},{"text": {"ja": "大きくする", "vi": "Làm lớn"}, "is_correct": false}], "explanation": {"ja": "繰り返すは「何度もする」という意味です。", "vi": "繰り返す có nghĩa là \"làm nhiều lần\"."}, "difficulty": "medium"}, {"question_number": 14, "type": "grammar", "question": {"ja": "「患者さんが _____ ている場合、医者に連絡します。」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんが _____ ている場合、医者に連絡します\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "眠", "vi": "ngủ"}, "is_correct": false},{"text": {"ja": "苦しむ", "vi": "khổ sở"}, "is_correct": true},{"text": {"ja": "笑う", "vi": "cười"}, "is_correct": false},{"text": {"ja": "歌う", "vi": "hát"}, "is_correct": false}], "explanation": {"ja": "患者さんが苦しんでいる場合は、医療的な対応が必要です。", "vi": "Khi bệnh nhân đang khổ sở, cần phải liên hệ bác sĩ."}, "difficulty": "medium"}, {"question_number": 15, "type": "vocabulary", "question": {"ja": "患者さんの回復は _____ です。", "vi": "Sự phục hồi của bệnh nhân là _____."}, "options": [{"text": {"ja": "順調", "vi": "suôn sẻ"}, "is_correct": true},{"text": {"ja": "危険", "vi": "nguy hiểm"}, "is_correct": false},{"text": {"ja": "複雑", "vi": "phức tạp"}, "is_correct": false},{"text": {"ja": "不可能", "vi": "không thể"}, "is_correct": false}], "explanation": {"ja": "患者さんの回復が順調 は良い状態を表します。", "vi": "患者さんの回復が順調 biểu hiện tình trạng tốt."}, "difficulty": "easy"}, {"question_number": 16, "type": "reading", "question": {"ja": "「緊急」の意味は？", "vi": "Ý nghĩa của \"緊急\" là?"}, "options": [{"text": {"ja": "ゆっくりである", "vi": "Chậm"}, "is_correct": false},{"text": {"ja": "すぐに対応が必要である", "vi": "Cần phải xử lý ngay lập tức"}, "is_correct": true},{"text": {"ja": "不可能である", "vi": "Không thể"}, "is_correct": false},{"text": {"ja": "簡単である", "vi": "Dễ dàng"}, "is_correct": false}], "explanation": {"ja": "緊急は「急いで対応する必要がある」という意味です。", "vi": "緊急 có nghĩa là \"cần xử lý ngay lập tức\"."}, "difficulty": "medium"}, {"question_number": 17, "type": "grammar", "question": {"ja": "「患者さんが _____ ために、介護職は手伝います。」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんが _____ ために、介護職は手伝います\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "大変な思いをしない", "vi": "không phải trải qua khó khăn"}, "is_correct": true},{"text": {"ja": "もっと大変になる", "vi": "trở nên khó khăn hơn"}, "is_correct": false},{"text": {"ja": "つまらない", "vi": "nhàm chán"}, "is_correct": false},{"text": {"ja": "怖くなる", "vi": "sợ hãi"}, "is_correct": false}], "explanation": {"ja": "介護職は患者さんが苦労しないために手伝います。", "vi": "Nhân viên chăm sóc giúp đỡ để bệnh nhân không phải khó khăn."}, "difficulty": "hard"}, {"question_number": 18, "type": "vocabulary", "question": {"ja": "患者さんは毎日、 _____ を測る必要があります。", "vi": "Bệnh nhân cần đo _____ mỗi ngày."}, "options": [{"text": {"ja": "脈拍", "vi": "nhịp tim"}, "is_correct": true},{"text": {"ja": "天気", "vi": "thời tiết"}, "is_correct": false},{"text": {"ja": "距離", "vi": "khoảng cách"}, "is_correct": false},{"text": {"ja": "時間", "vi": "thời gian"}, "is_correct": false}], "explanation": {"ja": "患者さんの健康管理のために、脈拍を測ります。", "vi": "Để quản lý sức khỏe bệnh nhân, đo nhịp tim mỗi ngày."}, "difficulty": "easy"}, {"question_number": 19, "type": "reading", "question": {"ja": "「迅速」と「遅い」は対義語ですか？", "vi": "\"迅速\" và \"遅い\" có phải từ trái nghĩa không?"}, "options": [{"text": {"ja": "はい、対義語です", "vi": "Vâng, là từ trái nghĩa"}, "is_correct": true},{"text": {"ja": "いいえ、同じ意味です", "vi": "Không, cùng ý nghĩa"}, "is_correct": false},{"text": {"ja": "時々対義語です", "vi": "Đôi khi là từ trái nghĩa"}, "is_correct": false},{"text": {"ja": "わかりません", "vi": "Tôi không biết"}, "is_correct": false}], "explanation": {"ja": "迅速は「速い」、遅いはその反対です。", "vi": "迅速 là \"nhanh\", 遅い là ngược lại."}, "difficulty": "medium"}, {"question_number": 20, "type": "grammar", "question": {"ja": "「患者さんが _____ から、介護職は注意します。」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんが _____ から、介護職は注意します\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "高齢である", "vi": "Cao tuổi"}, "is_correct": true},{"text": {"ja": "若い", "vi": "Trẻ"}, "is_correct": false},{"text": {"ja": "元気", "vi": "Khỏe mạnh"}, "is_correct": false},{"text": {"ja": "強い", "vi": "Mạnh"}, "is_correct": false}], "explanation": {"ja": "患者さんが高齢だから、介護職は特に注意が必要です。", "vi": "Vì bệnh nhân cao tuổi, nhân viên chăm sóc cần đặc biệt chú ý."}, "difficulty": "hard"}, {"question_number": 21, "type": "vocabulary", "question": {"ja": "患者さんは _____ しないでください、と言われました。", "vi": "Bệnh nhân được nói rằng không được _____."}, "options": [{"text": {"ja": "重い物を持つ", "vi": "Nâng vật nặng"}, "is_correct": true},{"text": {"ja": "水を飲む", "vi": "Uống nước"}, "is_correct": false},{"text": {"ja": "話す", "vi": "Nói chuyện"}, "is_correct": false},{"text": {"ja": "笑う", "vi": "Cười"}, "is_correct": false}], "explanation": {"ja": "患者さんの健康のために、重い物を持たないよう指導します。", "vi": "Để sức khỏe của bệnh nhân, được hướng dẫn không nâng vật nặng."}, "difficulty": "easy"}, {"question_number": 22, "type": "reading", "question": {"ja": "「誠実」の意味に最も近いのは？", "vi": "Ý nghĩa gần nhất với \"誠実\" là?"}, "options": [{"text": {"ja": "嘘をつく", "vi": "Nói dối"}, "is_correct": false},{"text": {"ja": "真心で接する", "vi": "Tiếp xúc với lòng chân thành"}, "is_correct": true},{"text": {"ja": "怠ける", "vi": "Lười biếng"}, "is_correct": false},{"text": {"ja": "無視する", "vi": "Bỏ qua"}, "is_correct": false}], "explanation": {"ja": "誠実は「真心で相手に接する」という意味です。", "vi": "誠実 có nghĩa là \"tiếp xúc với người khác bằng lòng chân thành\"."}, "difficulty": "medium"}, {"question_number": 23, "type": "grammar", "question": {"ja": "「患者さんの _____ が、介護職の頑張りです。」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんの _____ が、介護職の頑張りです\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "回復", "vi": "Phục hồi"}, "is_correct": true},{"text": {"ja": "悪化", "vi": "Xấu đi"}, "is_correct": false},{"text": {"ja": "不安", "vi": "Lo lắng"}, "is_correct": false},{"text": {"ja": "痛み", "vi": "Đau"}, "is_correct": false}], "explanation": {"ja": "患者さんの回復が、介護職の努力の結果です。", "vi": "Sự phục hồi của bệnh nhân là kết quả của nỗ lực nhân viên chăm sóc."}, "difficulty": "medium"}, {"question_number": 24, "type": "vocabulary", "question": {"ja": "患者さんの家族は毎日、 _____ に来ます。", "vi": "Gia đình bệnh nhân đến _____每日。"}, "options": [{"text": {"ja": "病院", "vi": "bệnh viện"}, "is_correct": true},{"text": {"ja": "公園", "vi": "công viên"}, "is_correct": false},{"text": {"ja": "学校", "vi": "trường học"}, "is_correct": false},{"text": {"ja": "図書館", "vi": "thư viện"}, "is_correct": false}], "explanation": {"ja": "患者さんの家族が毎日来る場所は、病院です。", "vi": "Nơi gia đình bệnh nhân đến mỗi ngày là bệnh viện."}, "difficulty": "easy"}, {"question_number": 25, "type": "reading", "question": {"ja": "「信頼」の意味は？", "vi": "Ý nghĩa của \"信頼\" là?"}, "options": [{"text": {"ja": "疑う", "vi": "Nghi ngờ"}, "is_correct": false},{"text": {"ja": "相手を信じる", "vi": "Tin tưởng vào người khác"}, "is_correct": true},{"text": {"ja": "遠い関係", "vi": "mối quan hệ xa"}, "is_correct": false},{"text": {"ja": "敵である", "vi": "Là kẻ thù"}, "is_correct": false}], "explanation": {"ja": "信頼は「相手を信じる」という意味です。", "vi": "信頼 có nghĩa là \"tin tưởng vào người khác\"."}, "difficulty": "easy"}, {"question_number": 26, "type": "grammar", "question": {"ja": "「患者さんが _____ ながら、散歩します。」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんが _____ ながら、散歩します\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "話す", "vi": "nói chuyện"}, "is_correct": true},{"text": {"ja": "食べる", "vi": "ăn"}, "is_correct": false},{"text": {"ja": "寝る", "vi": "ngủ"}, "is_correct": false},{"text": {"ja": "飲む", "vi": "uống"}, "is_correct": false}], "explanation": {"ja": "患者さんが話しながら散歩するのは自然です。", "vi": "Bệnh nhân nói chuyện khi đi bộ là tự nhiên."}, "difficulty": "medium"}, {"question_number": 27, "type": "vocabulary", "question": {"ja": "患者さんは _____ に同意しました。", "vi": "Bệnh nhân đã đồng ý với _____."}, "options": [{"text": {"ja": "医者のアドバイス", "vi": "lời khuyên của bác sĩ"}, "is_correct": true},{"text": {"ja": "物騒な計画", "vi": "kế hoạch nguy hiểm"}, "is_correct": false},{"text": {"ja": "不健康な行動", "vi": "hành động không lành mạnh"}, "is_correct": false},{"text": {"ja": "危険な提案", "vi": "đề xuất nguy hiểm"}, "is_correct": false}], "explanation": {"ja": "患者さんが同意するのは、医者のアドバイスなど健康的な決定です。", "vi": "Bệnh nhân đồng ý với những quyết định lành mạnh như lời khuyên của bác sĩ."}, "difficulty": "medium"}, {"question_number": 28, "type": "reading", "question": {"ja": "介護職が患者さんに最初にすることは？", "vi": "Điều đầu tiên nhân viên chăm sóc làm với bệnh nhân là?"}, "options": [{"text": {"ja": "患者さんに命令する", "vi": "Lệnh bệnh nhân"}, "is_correct": false},{"text": {"ja": "丁寧に挨拶し、患者さんの状態を確認する", "vi": "Chào hỏi lịch sự và kiểm tra tình trạng bệnh nhân"}, "is_correct": true},{"text": {"ja": "患者さんを無視する", "vi": "Bỏ qua bệnh nhân"}, "is_correct": false},{"text": {"ja": "患者さんに怒る", "vi": "Tức giận bệnh nhân"}, "is_correct": false}], "explanation": {"ja": "介護職の第一歩は、患者さんへの敬意と信頼を示すことです。", "vi": "Bước đầu tiên của nhân viên chăm sóc là thể hiện sự tôn trọng và tin tưởng vào bệnh nhân."}, "difficulty": "medium"}, {"question_number": 29, "type": "grammar", "question": {"ja": "「患者さんが _____ ない場合、医者に連絡します。」に最も適切なのは？", "vi": "Để hoàn thành \"患者さんが _____ ない場合、医者に連絡します\", lựa chọn phù hợp nhất là?"}, "options": [{"text": {"ja": "回復する", "vi": "phục hồi"}, "is_correct": true},{"text": {"ja": "元気になる", "vi": "trở nên khỏe mạnh"}, "is_correct": false},{"text": {"ja": "運動する", "vi": "tập thể dục"}, "is_correct": false},{"text": {"ja": "食べる", "vi": "ăn"}, "is_correct": false}], "explanation": {"ja": "患者さんが回復しない場合は、医療的な介入が必要です。", "vi": "Nếu bệnh nhân không phục hồi, cần can thiệp y tế."}, "difficulty": "hard"}, {"question_number": 30, "type": "reading", "question": {"ja": "患者さんと介護職の関係は、どのような関係ですか？", "vi": "Mối quan hệ giữa bệnh nhân và nhân viên chăm sóc là?"}, "options": [{"text": {"ja": "敵である", "vi": "Là kẻ thù"}, "is_correct": false},{"text": {"ja": "信頼と相互尊重に基づく関係", "vi": "Mối quan hệ dựa trên tin tưởng và tôn trọng lẫn nhau"}, "is_correct": true},{"text": {"ja": "金銭関係のみ", "vi": "Chỉ là mối quan hệ tài chính"}, "is_correct": false},{"text": {"ja": "親戚である", "vi": "Là họ hàng"}, "is_correct": false}], "explanation": {"ja": "患者さんと介護職の関係は、信頼と相互尊重の上に成り立ちます。", "vi": "Mối quan hệ giữa bệnh nhân và nhân viên chăm sóc dựa trên tin tưởng và tôn trọng lẫn nhau."}, "difficulty": "hard"}]}' );

